impl.spec_text:
use vstd::prelude::*;

mod log {
    use vstd::prelude::*;
    pub struct Device{
        pub dev: Vec<u8>,
        size: usize,
        head: usize,
        pub tail: usize,
    }

    impl Device {
        pub fn new(size: usize) -> Self
        {
            Self {
                dev: Vec::with_capacity(size),
                size,
                head: 0,
                tail: 0,
            }
        }

        pub fn write_byte(&mut self, dst: usize, byte: u8)
            requires
                dst < old(self).dev.len()
        {
            self.dev.set(dst, byte);
        }
    }
}

use crate::log::*;

impl.impl_text:
fn main() {
    let mut dev = Device::new(4096);
    dev.write_byte(0, 0);
}
